-- Status messages for the CLI status bar (Squashed 006-009).
-- Idempotent (INSERT OR IGNORE).

-- Tips
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Tip: Use /undo to delete the last check.', 'tip');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Tip: /review helps you practice due cards.', 'tip');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Tip: Use /stats to see your progress across 28 error types.', 'tip');
