INSERT INTO status_messages (content, type) VALUES ('Tip: Use /gemini-pro for higher-quality handbook generation.', 'tip');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Tip: IGT handles rate limits for major LLM providers automatically.', 'tip');
