-- Grammar Facts
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "I am" is the shortest complete sentence in the English language.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "The quick brown fox jumps over the lazy dog" is a pangram, using every letter in the alphabet.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "Queueing" is the only word in English with five consecutive vowels.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The most commonly used word in English is "the".', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "Set" has more definitions than any other word in the English language.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The word "alphabet" comes from the first two letters of the Greek alphabet: alpha and beta.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "Underground" is the only word in the English language that begins and ends with the letters "und."', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Article Usage) The word "the" is a definite article; "a" and "an" are indefinite articles.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Punctuation) The Oxford Comma is the final comma in a list of three or more items.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Spelling) "I before E except after C" is a common rule, but it has many exceptions like "weird".', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The word "uncopyrightable" is the longest English word that can be written without repeating a letter.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "Screeched" is the longest one-syllable word in the English language.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The "dot" over the letter "i" or "j" is called a tittle.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "Dreamt" is the only English word that ends in the letters "mt".', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: English is the official language of 67 different countries.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: A new word is added to the dictionary approximately every two hours.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The shortest, oldest, and most commonly used word is "I".', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "Almost" is the longest word in English with all the letters in alphabetical order.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "Rhythm" is the longest English word without a real vowel (a, e, i, o, u).', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: A "pangram" sentence is one that contains every letter in the language.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "E" is the most common letter in the English language.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The word "swims" will be "swims" even when turned upside down.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The symbol "@" is officially called an "asperand" or an "ampersat".', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Subject-Verb) Collective nouns like "team" can be singular or plural depending on the dialect.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Prepositions) Ending a sentence with a preposition is actually acceptable in modern English.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Adjectives) There is a standard order for adjectives: opinion, size, age, shape, color, origin, material, purpose.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Pronouns) "They" has been used as a singular pronoun since at least the 14th century.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Verbs) The verb "to be" is the most irregular verb in the English language.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Punctuation) The "interrobang" is a non-standard punctuation mark that combines a question mark and an exclamation point.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The longest word in any of the major English dictionaries is "pneumonoultramicroscopicsilicovolcanoconiosis".', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The word "mortgage" comes from a French word meaning "death pledge".', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The words "skunk", "papoose", and "squash" are all Native American in origin.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: Shakespeare added over 1,700 words to the English language.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "Goodbye" originally comes from the Old English phrase "God be with ye".', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The average person knows about 20,000 to 35,000 words.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: More people have learned English as a second language than there are native speakers.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The word "set" has the most meanings of any word in English.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "Typewriter" is the longest word you can make using only the top row of a QWERTY keyboard.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The word "checkmate" in chess comes from the Persian phrase "Shah Mat," meaning "the king is helpless."', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "Town" is the oldest word in the English language that is still used today.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The most used adjective in English is "good".', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The word "news" was once considered plural, and you could say "the news are bad."', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "Oxymoron" is itself an oxymoron; in Greek, "oxys" means sharp and "moros" means stupid.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The word "robot" comes from the Czech word for "forced labor."', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: English used to have grammatical gender (like German or French) until the 1200s.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The pilcrow (¶) is the symbol used to denote a new paragraph.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Verb Tense) The present perfect tense connects the past to the present.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Word Form) Adverbs often end in "-ly", but not all of them do (e.g., "fast", "well").', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Comparison) "Unique" technically shouldn''t be compared (no "more unique").', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Negation) Avoid double negatives in formal writing as they can cancel each other out.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The word "shampoo" comes from a Hindi word meaning "to massage".', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "Go" is the shortest complete sentence in the English language.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "Subbookkeeper" is the only word with four consecutive double letters.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The word "nerd" was first coined by Dr. Seuss in 1950.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "Ewe" and "you" are pronounced exactly the same but have no letters in common.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The word "clue" originally meant a ball of thread.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Nouns) "Data" was originally the plural of "datum," but is now often used as a singular mass noun.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Prepositions) "Into" implies movement toward the inside; "in" implies position.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Subject-Verb) "The number of..." takes a singular verb; "A number of..." takes a plural verb.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Articles) Names of most countries do not take an article, but "The United States" and "The Netherlands" do.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The dot on top of "i" and "j" is officially called a "tittle".', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "Facetious" contains all the vowels in alphabetical order.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The word "trivia" comes from the Latin for "three roads".', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Spelling) "Accommodate" has two "c"s and two "m"s.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Punctuation) The "slash" (/) is also known as a virgule.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The word "lucid" comes from the Latin word for "light".', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "Dreamt" is the only English word ending in "mt".', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Verbs) "Will" and "shall" used to have different rules for different persons, but they are now mostly interchangeable.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Nouns) "Physics" and "Mathematics" are singular despite ending in "s".', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: English has the largest vocabulary of any language in the world.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: About 4,000 words are added to the dictionary every year.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "Stewardesses" is the longest word that can be typed with only the left hand.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "Lol" was added to the Oxford English Dictionary in 2011.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Adjectives) "Oldest" is used for age; "eldest" is specifically for family members.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Pronouns) "Mine" and "Yours" are possessive pronouns; they do not use apostrophes.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "Listen" is an anagram of "silent".', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The word "alphabet" is derived from the first two Greek letters.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Word Order) Adverbs of frequency (like "always") usually go before the main verb.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Tense) The past perfect tense ("had done") describes an action completed before another past action.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Conjunctions) "Unless" means "if not".', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: The word "synonym" does not have a synonym (mostly).', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: (Clarity) Avoid "empty" subjects like "It is..." to make your writing more direct.', 'grammar_fact');
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('Grammar Fact: "Rhythms" is the longest word without a vowel (excluding "y").', 'grammar_fact');

-- Quotes
INSERT OR IGNORE INTO status_messages (content, type) VALUES ('"The limits of my language mean the limits of my world." — Ludwig Wittgenstein', 'quote');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"To have another language is to possess a second soul."', 'quote', 'Charlemagne');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Language is the blood of the soul into which thoughts run and out of which they grow."', 'quote', 'Oliver Wendell Holmes');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"One language sets you in a corridor for life. Two languages open every door along the way."', 'quote', 'Frank Smith');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Knowledge of languages is the doorway to wisdom."', 'quote', 'Roger Bacon');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Change your language and you change your thoughts."', 'quote', 'Karl Albrecht');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Learning is a treasure that will follow its owner everywhere."', 'quote', 'Chinese Proverb');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"The limits of my language mean the limits of my world."', 'quote', 'Ludwig Wittgenstein');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"A different language is a different vision of life."', 'quote', 'Federico Fellini');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Language is the road map of a culture. It tells you where its people come from and where they are going."', 'quote', 'Rita Mae Brown');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"If you talk to a man in a language he understands, that goes to his head. If you talk to him in his language, that goes to his heart."', 'quote', 'Nelson Mandela');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Language is wine upon the lips."', 'quote', 'Virginia Woolf');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"You can never understand one language until you understand at least two."', 'quote', 'Geoffrey Willans');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Language exerts hidden power, like a moon on the tides."', 'quote', 'Rita Mae Brown');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"A man who knows two languages is worth two men."', 'quote', 'French Proverb');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"The more languages you know, the more you are human."', 'quote', 'Tomáš Garrigue Masaryk');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Language is the light of the mind."', 'quote', 'John Stuart Mill');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"To learn a language is to have one more window from which to look at the world."', 'quote', 'Chinese Proverb');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Words are a pretext. It is the inner bond that draws one person to another, not words."', 'quote', 'Rumi');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Language is the soul of intellect, and writing is the embodyment of language."', 'quote', 'Samuel Johnson');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"The soul of a people is found in its language."', 'quote', 'Johann Gottfried von Herder');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Without language, one cannot talk to people and understand them; one cannot share their hopes and aspirations."', 'quote', 'Nelson Mandela');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Language is the apparel in which your thoughts parade before the public."', 'quote', 'George Crane');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"The beauty of a language is in the words; the spirit is in the grammar."', 'quote', 'Unknown');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"A language is not just a body of vocabulary or a set of grammatical rules. A language is a flash of the human spirit."', 'quote', 'Wade Davis');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Grammar is the logic of speech, even as logic is the grammar of reason."', 'quote', 'Richard Chenevix Trench');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Language is the mirror of the mind."', 'quote', 'Noam Chomsky');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"A language is a system of responses of a people to its environment."', 'quote', 'Jose Rizal');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Words are the small change of thought."', 'quote', 'Jules Renard');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Language is the key to the heart of the people."', 'quote', 'Unknown');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Every language is a world. Without it, the world is incomplete."', 'quote', 'Unknown');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Words are, of course, the most powerful drug used by mankind."', 'quote', 'Rudyard Kipling');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Mistakes are the portals of discovery."', 'quote', 'James Joyce');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Language is a process of free creation; its laws and principles are fixed, but the manner in which the principles of generation are used is free and infinitely varied."', 'quote', 'Noam Chomsky');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"The word ''listen'' contains the same letters as the word ''silent''."', 'quote', 'Alfred Brendel');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"A language is a system of arbitrary vocal symbols by means of which a social group cooperates."', 'quote', 'Bernard Bloch');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"The structure of a language determines the way in which speakers of that language perceive the world."', 'quote', 'Benjamin Lee Whorf');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Slang is a language that rolls up its sleeves, spits on its hands and goes to work."', 'quote', 'Carl Sandburg');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Language is a city to the building of which every human being brought a stone."', 'quote', 'Ralph Waldo Emerson');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Words are but symbols for the relations of things to one another and to us; nowhere do they touch upon absolute truth."', 'quote', 'Friedrich Nietzsche');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Proper words in proper places, make the true definition of a style."', 'quote', 'Jonathan Swift');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"All language is but a poor translation."', 'quote', 'Franz Kafka');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"The difference between the right word and the almost right word is the difference between lightning and a lightning bug."', 'quote', 'Mark Twain');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Language is the mother of thought, not its handmaid."', 'quote', 'Karl Kraus');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Words are the voice of the heart."', 'quote', 'Confucius');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Kind words can be short and easy to speak, but their echoes are truly endless."', 'quote', 'Mother Teresa');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"The Pen is mightier than the Sword."', 'quote', 'Edward Bulwer-Lytton');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Good words are worth much, and cost little."', 'quote', 'George Herbert');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"The word is half his that speaks, and half his that hears it."', 'quote', 'Michel de Montaigne');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"A word is not a crystal, transparent and unchanged; it is the skin of a living thought."', 'quote', 'Oliver Wendell Holmes Jr.');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Language is the invention of people who want to catch and hold the world."', 'quote', 'Unknown');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Without words, without writing and without books there would be no history, there could be no concept of humanity."', 'quote', 'Hermann Hesse');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Language is a tool of the mind."', 'quote', 'Unknown');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"A nation is a group of people who share the same language and the same history."', 'quote', 'Unknown');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"The first step toward wisdom is calling things by their right names."', 'quote', 'Chinese Proverb');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Language is the dress of thought."', 'quote', 'Samuel Johnson');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Words are the pegs to hang ideas on."', 'quote', 'Henry Ward Beecher');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"One forgetful word can seal a fate."', 'quote', 'Unknown');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"The turn of a sentence can change a mood."', 'quote', 'Unknown');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Words have the power to both destroy and heal."', 'quote', 'Buddha');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"In the beginning was the Word."', 'quote', 'Bible');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Language is the house of being."', 'quote', 'Martin Heidegger');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"The limits of my language are the limits of my mind."', 'quote', 'Unknown');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Talk is cheap, but words are precious."', 'quote', 'Unknown');
INSERT OR IGNORE INTO status_messages (content, type, author) VALUES ('"Silence is the language of God, all else is poor translation."', 'quote', 'Rumi');
